#include <bits/stdc++.h>
using namespace std;

const int MaxN = 1e5 + 10;

int days[MaxN], trials[MaxN], score[MaxN];

void solve() {
    int numParticipants, maxDays;
    cin >> numParticipants >> maxDays;

    vector<pair<int, int>> participants;
    long long totalScore = 0;

    for (int i = 0; i < numParticipants; ++i) {
        cin >> days[i] >> trials[i] >> score[i];
        participants.push_back({score[i], i});
        totalScore += 1LL * score[i] * trials[i];
    }

    sort(participants.rbegin(), participants.rend());

    set<int> availableDays;
    for (int i = 1; i <= maxDays; ++i) {
        availableDays.insert(i);
    }

    for (auto &participant : participants) {
        int participantIndex = participant.second;
        while (trials[participantIndex] > 0) {
            auto it = availableDays.lower_bound(days[participantIndex]);
            if (it == availableDays.end()) {
                break;
            }
            availableDays.erase(it);
            totalScore -= score[participantIndex];
            trials[participantIndex]--;
        }
    }

    cout << totalScore << '\n';
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(NULL);

    int t;
    cin>>t;
    assert(t >= 1 && t <= 10);

    while (t--) {
        solve();
    }

    return 0;
}

