#include <stdio.h>
#include <stdlib.h>

typedef struct {
    int arrivalDay;
    int totalLectures;
    int sadness;
} Trainer;

// Function to compare trainers by arrival day for sorting
int compareTrainers(const void* a, const void* b) {
    return ((Trainer*)a)->arrivalDay - ((Trainer*)b)->arrivalDay;
}

// Max heap to store trainers based on sadness per untaught lecture
typedef struct {
    Trainer* trainers;
    int size;
    int capacity;
} MaxHeap;

// Function to create a max heap
MaxHeap* createMaxHeap(int capacity) {
    MaxHeap* heap = (MaxHeap*)malloc(sizeof(MaxHeap));
    heap->capacity = capacity;
    heap->size = 0;
    heap->trainers = (Trainer*)malloc(capacity * sizeof(Trainer));
    return heap;
}

// Function to swap two trainers
void swap(Trainer* a, Trainer* b) {
    Trainer temp = *a;
    *a = *b;
    *b = temp;
}

// Function to heapify up
void heapifyUp(MaxHeap* heap, int index) {
    while (index > 0) {
        int parent = (index - 1) / 2;
        if (heap->trainers[index].sadness > heap->trainers[parent].sadness) {
            swap(&heap->trainers[index], &heap->trainers[parent]);
            index = parent;
        } else {
            break;
        }
    }
}

// Function to insert a trainer into the max heap
void insert(MaxHeap* heap, Trainer trainer) {
    if (heap->size == heap->capacity) {
        heap->capacity *= 2;
        heap->trainers = (Trainer*)realloc(heap->trainers, heap->capacity * sizeof(Trainer));
    }
    heap->trainers[heap->size] = trainer;
    heap->size++;
    heapifyUp(heap, heap->size - 1);
}

// Function to extract the maximum trainer (the one with the highest sadness)
Trainer extractMax(MaxHeap* heap) {
    Trainer maxTrainer = heap->trainers[0];
    heap->trainers[0] = heap->trainers[heap->size - 1];
    heap->size--;
    // We need to heapify down from the root now
    int index = 0;
    while (index < heap->size) {
        int left = 2 * index + 1;
        int right = 2 * index + 2;
        int largest = index;

        if (left < heap->size && heap->trainers[left].sadness > heap->trainers[largest].sadness) {
            largest = left;
        }
        if (right < heap->size && heap->trainers[right].sadness > heap->trainers[largest].sadness) {
            largest = right;
        }
        if (largest != index) {
            swap(&heap->trainers[index], &heap->trainers[largest]);
            index = largest;
        } else {
            break;
        }
    }
    return maxTrainer;
}

// Function to check if the heap is empty
int isEmpty(MaxHeap* heap) {
    return heap->size == 0;
}

int main() {
    int T;
    scanf("%d", &T);

    while (T--) {
        int N, D;
        scanf("%d %d", &N, &D);

        Trainer* trainers = (Trainer*)malloc(N * sizeof(Trainer));
        for (int i = 0; i < N; i++) {
            scanf("%d %d %d", &trainers[i].arrivalDay, &trainers[i].totalLectures, &trainers[i].sadness);
        }

        // Sort trainers by their arrival day
        qsort(trainers, N, sizeof(Trainer), compareTrainers);

        MaxHeap* maxHeap = createMaxHeap(N);
        long long totalSadness = 0;
        int currentTrainerIndex = 0;

        for (int day = 1; day <= D; day++) {
            // Add trainers available on this day to the heap
            while (currentTrainerIndex < N && trainers[currentTrainerIndex].arrivalDay <= day) {
                insert(maxHeap, trainers[currentTrainerIndex]);
                currentTrainerIndex++;
            }

            // If there's a trainer available, let them teach a lecture
            if (!isEmpty(maxHeap)) {
                Trainer top = extractMax(maxHeap);
                top.totalLectures--; // Reduce the remaining lectures by 1
                // If they still have lectures left, put them back into the heap
                if (top.totalLectures > 0) {
                    insert(maxHeap, top);
                }
            }
        }

        // Calculate remaining sadness
        while (!isEmpty(maxHeap)) {
            Trainer top = extractMax(maxHeap);
            totalSadness += (long long)top.totalLectures * top.sadness; // sadness per lecture * remaining lectures
        }

        printf("%lld\n", totalSadness);
        free(maxHeap->trainers);
        free(maxHeap);
        free(trainers);
    }

    return 0;
}

