import java.util.*;
import java.lang.*;
import java.io.*;

class Codechef {
    static final int MaxN = (int)1e5 + 10;

    static int[] days = new int[MaxN];
    static int[] trials = new int[MaxN];
    static int[] score = new int[MaxN];

    public static void solve(Scanner sc) {
        int numParticipants = sc.nextInt();
        int maxDays = sc.nextInt();

        List<Pair> participants = new ArrayList<>();
        long totalScore = 0;

        for (int i = 0; i < numParticipants; ++i) {
            days[i] = sc.nextInt();
            trials[i] = sc.nextInt();
            score[i] = sc.nextInt();
            participants.add(new Pair(score[i], i));
            totalScore += (long) score[i] * trials[i];
        }

        participants.sort((a, b) -> Integer.compare(b.score, a.score)); // Sort in descending order by score

        TreeSet<Integer> availableDays = new TreeSet<>();
        for (int i = 1; i <= maxDays; ++i) {
            availableDays.add(i);
        }

        for (Pair participant : participants) {
            int participantIndex = participant.index;
            while (trials[participantIndex] > 0) {
                Integer it = availableDays.ceiling(days[participantIndex]);
                if (it == null) {
                    break;
                }
                availableDays.remove(it);
                totalScore -= score[participantIndex];
                trials[participantIndex]--;
            }
        }

        System.out.println(totalScore);
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int t = sc.nextInt();
        assert t >= 1 && t <= 10;

        while (t-- > 0) {
            solve(sc);
        }

        sc.close();
    }

    static class Pair {
        int score;
        int index;

        Pair(int score, int index) {
            this.score = score;
            this.index = index;
        }
    }
}

