const readline = require('readline');

const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});

const MaxN = 1e5 + 10;
const days = new Array(MaxN).fill(0);
const trials = new Array(MaxN).fill(0);
const score = new Array(MaxN).fill(0);

function solve(numParticipants, maxDays, input) {
    const participants = [];
    let totalScore = BigInt(0);

    for (let i = 0; i < numParticipants; ++i) {
        days[i] = input[i][0];
        trials[i] = input[i][1];
        score[i] = input[i][2];
        participants.push([score[i], i]);
        totalScore += BigInt(score[i]) * BigInt(trials[i]);
    }

    participants.sort((a, b) => b[0] - a[0]);

    const availableDays = new Set();
    for (let i = 1; i <= maxDays; ++i) {
        availableDays.add(i);
    }

    for (const [participantScore, participantIndex] of participants) {
        while (trials[participantIndex] > 0) {
            const day = Array.from(availableDays).find(d => d >= days[participantIndex]);
            if (day === undefined) {
                break;
            }
            availableDays.delete(day);
            totalScore -= BigInt(score[participantIndex]);
            trials[participantIndex]--;
        }
    }

    console.log(totalScore.toString());
}

let inputLines = [];
let currentLine = 0;

rl.on('line', (line) => {
    inputLines.push(line.trim());
});

rl.on('close', () => {
    const t = parseInt(inputLines[currentLine++]);

    for (let testCase = 0; testCase < t; testCase++) {
        const [numParticipants, maxDays] = inputLines[currentLine++].split(' ').map(Number);
        const input = [];

        for (let i = 0; i < numParticipants; i++) {
            input.push(inputLines[currentLine++].split(' ').map(Number));
        }

        solve(numParticipants, maxDays, input);
    }
});
